---支付绿钞方法
---@userId 玩家
---@golds 绿钞数量
---@successCallback 支付成功回调函数
function PayHelper.payCurrency(player, price, successCallback)
    if player:getCurrency() < price then
        return
    end
    player:subCurrency(price)
    if successCallback then
        successCallback()
    end
end

function PayHelper.payMoney(player, uniqueId, coinId, price, successCallback, failedCallback, subKey)
    if coinId == PayType.Diamonds then
        PayHelper.payDiamondsSync(player.userId, uniqueId, price, successCallback, failedCallback, subKey)
        return
    end
    if coinId == PayType.Golds then
        PayHelper.payGoldsSync(player.userId, uniqueId, price, successCallback, failedCallback, subKey)
        return
    end
    if coinId == PayType.Currency then
        PayHelper.payCurrency(player, price, successCallback)
        return
    end
end